async (page) => {
  // Check what tiles are walkable south of current position
  const result = await page.evaluate(() => {
    const map = window.game && window.game.map;
    if (!map) return 'no map';
    const checks = [];
    for (let y = 170; y <= 200; y++) {
      for (let x = 252; x <= 265; x++) {
        const coll = map.isColliding(x, y);
        if (!coll) {
          checks.push(`(${x},${y})=walkable`);
        }
      }
    }
    return checks.slice(0, 60).join(', ');
  });
  return result;
}

