async (page) => {
  // Try clicking the door tile at (260, 228) - directly north of current position
  const result = await page.evaluate(() => {
    const r = window.game.renderer, cam = r.camera, scale = r.actualTileSize / r.tileSize;
    const tx = 260, ty = 228;
    const sx = (tx * r.tileSize - cam.x) * scale;
    const sy = (ty * r.tileSize - cam.y) * scale;
    const w = r.canvasWidth || 1296, h = r.canvasHeight || 768;

    if (sx >= 0 && sx <= w && sy >= 0 && sy <= h) {
      document.getElementById('entities').dispatchEvent(new MouseEvent('click', {clientX: sx, clientY: sy, bubbles: true, ctrlKey: false}));
      return {ok: true, sx, sy};
    }
    return {ok: false, sx, sy};
  });

  await page.waitForTimeout(2000);
  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });

  const pos = await page.evaluate(() => ({x: window.game.player.gridX, y: window.game.player.gridY}));

  // Check quest details
  const questInfo = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const q = gs?.quests?.find(q => q.key === 'desertquest');
    return q;
  });

  return JSON.stringify({result, pos, questInfo});
}

