async (page) => {
  // Inspect game achievement system
  const result = await page.evaluate(() => {
    const info = {};
    // Check if there's an achievement menu
    const achMenu = window.game?.menu?.achievements;
    if (achMenu) {
      info.hasAchMenu = true;
      info.achMenuKeys = Object.keys(achMenu);
    }
    // Check notification system
    const notif = window.game?.menu?.notification;
    info.hasNotif = !!notif;
    // Check for quest/achievement related DOM elements
    const questPanel = document.getElementById('quest-container');
    const achPanel = document.getElementById('achievements');
    const achievePanel = document.getElementById('achievement-container');
    info.questPanel = !!questPanel;
    info.achPanel = !!achPanel;
    info.achievePanel = !!achievePanel;
    // Scan all IDs that contain 'ach' or 'achieve'
    const allEls = document.querySelectorAll('[id]');
    const achEls = [];
    allEls.forEach(el => {
      if (el.id.toLowerCase().includes('ach') || el.id.toLowerCase().includes('achieve')) {
        achEls.push({id: el.id, tag: el.tagName, class: el.className.toString().slice(0,50)});
      }
    });
    info.achEls = achEls;
    return JSON.stringify(info);
  });
  return result;
}

